/**
 * @name Eval data flow analysis in ImageMath
 * @description Analyze data flow to eval() in PIL.ImageMath
 * @kind path-problem
 * @problem.severity error
 * @id py/imagemath-eval-flow
 * @tags security
 *        external/cwe/cwe-094
 */

import python
import semmle.python.dataflow.new.DataFlow
import semmle.python.dataflow.new.TaintTracking
import semmle.python.dataflow.new.RemoteFlowSources
import semmle.python.Concepts

module EvalFlowConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    exists(Call c |
      c.getFunc().(Name).getId() = "eval" and
      sink = DataFlow::exprNode(c)
    )
  }
}

module EvalFlow = TaintTracking::Global<EvalFlowConfig>;
import EvalFlow::PathGraph

from EvalFlow::PathNode source, EvalFlow::PathNode sink
where EvalFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "User input flows to eval() at $@.", source.getNode(), "input source"
